        continue

    # Check Bike Parking
    bike_parking = False
    if 'BikeParking' in attrs:
        val = attrs['BikeParking']
        if val == 'True':
            bike_parking = True

    # Check Business Parking
    business_parking = False
    if 'BusinessParking' in attrs:
        val = attrs['BusinessParking']
        if val == 'True':
            business_parking = True
        elif isinstance(val, str) and val.startswith('{'):
            # Check if 'True' is in the string representation
            if 'True' in val:
                business_parking = True

    if bike_parking or business_parking:
        count += 1

print("__RESULT__:")
print(count)

